{"file_path":"/home/user/workspace/run.py","content":"import asyncio


async def run_tasks(tasks, max_concurrent):
    """Run a list of async callables with a concurrency limit.

    Args:
        tasks: List of zero-argument async callables to run.
        max_concurrent: Maximum number of tasks running at any time.

    Raises:
        ValueError: If max_concurrent is less than 1.
        The first non-CancelledError exception raised by any task, after
        allowing any already-running tasks to run their cleanup code.
    """
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    pending = set()
    tasks_iter = iter(tasks)

    # Seed the initial batch — up to max_concurrent tasks.
    try:
        for _ in range(max_concurrent):
            pending.add(asyncio.create_task(next(tasks_iter)()))
    except StopIteration:
        pass

    try:
        while pending:
            done, pending = await asyncio.wait(
                pending, return_when=asyncio.FIRST_COMPLETED,
            )

            # If a task failed with a real exception (not CancelledError),
            # cancel the remaining pending tasks, wait for their cleanup,
            # and propagate the original exception.
            for d in done:
                if d.cancelled():
                    continue
                exc = d.exception()
                if exc is not None:
                    for t in pending:
                        t.cancel()
                    if pending:
                        await asyncio.wait(pending)
                    raise exc

            # Start one new task for each completed slot.
            for _ in done:
                try:
                    pending.add(asyncio.create_task(next(tasks_iter)()))
                except StopIteration:
                    pass

    except asyncio.CancelledError:
        # Cancellation was requested (e.g. KeyboardInterrupt via asyncio.run).
        # Let already-started tasks finish so their cleanup (finally blocks,
        # context manager __exit__) runs.  Do NOT start any queued tasks.
        if pending:
            await asyncio.wait(pending)
        raise
